import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { ReactiveFormsModule, FormBuilder } from '@angular/forms';
import { CourseCardComponent, CourseCardVm } from '../course-card/course-card.component';

@Component({
  selector: 'app-courses',
  standalone: true,
  imports: [CommonModule, RouterModule, ReactiveFormsModule, CourseCardComponent],
  templateUrl: './courses.component.html',
  styleUrls: ['./courses.component.scss']
})
export class CoursesComponent {
  private fb = new FormBuilder();

  isLoading = signal(true);

  categories = signal<string[]>([
    'Mathématiques',
    'Physique-Chimie',
    'Français',
    'Anglais',
    'Informatique'
  ]);

  levels = signal<string[]>(['1ère année', '2ème année', '3ème année', 'Bac']);

  filtersForm = this.fb.group({
    search: this.fb.control<string>('', { nonNullable: true }),
    category: this.fb.control<string>('', { nonNullable: true }),
    level: this.fb.control<string>('', { nonNullable: true })
  });

  private allCourses = signal<CourseCardVm[]>([
    {
      id: 'c1',
      title: 'Algèbre — Bases et exercices',
      teacherName: 'M. Amine',
      durationMin: 95,
      levelName: '2ème année',
      categoryName: 'Mathématiques',
      coverUrl: 'https://images.unsplash.com/photo-1509228468518-180dd4864904?auto=format&fit=crop&w=1200&q=60'
    },
    {
      id: 'c2',
      title: 'Physique — Mécanique (cinématique)',
      teacherName: 'Mme Salma',
      durationMin: 120,
      levelName: '3ème année',
      categoryName: 'Physique-Chimie',
      coverUrl: 'https://images.unsplash.com/photo-1532094349884-543bc11b234d?auto=format&fit=crop&w=1200&q=60'
    },
    {
      id: 'c3',
      title: 'Français — Compréhension & Production écrite',
      teacherName: 'M. Karim',
      durationMin: 70,
      levelName: '1ère année',
      categoryName: 'Français',
      coverUrl: 'https://images.unsplash.com/photo-1524995997946-a1c2e315a42f?auto=format&fit=crop&w=1200&q=60'
    },
    {
      id: 'c4',
      title: 'Anglais — Grammar Essentials',
      teacherName: 'Ms. Sarah',
      durationMin: 80,
      levelName: '2ème année',
      categoryName: 'Anglais',
      coverUrl: 'https://images.unsplash.com/photo-1523240795612-9a054b0db644?auto=format&fit=crop&w=1200&q=60'
    },
    {
      id: 'c5',
      title: 'Informatique — Introduction à l’algorithmique',
      teacherName: 'M. Youssef',
      durationMin: 110,
      levelName: 'Bac',
      categoryName: 'Informatique',
      coverUrl: 'https://images.unsplash.com/photo-1518770660439-4636190af475?auto=format&fit=crop&w=1200&q=60'
    },
    {
      id: 'c6',
      title: 'Mathématiques — Géométrie analytique',
      teacherName: 'Mme Inès',
      durationMin: 105,
      levelName: '3ème année',
      categoryName: 'Mathématiques',
      coverUrl: 'https://images.unsplash.com/photo-1526374965328-7f61d4dc18c5?auto=format&fit=crop&w=1200&q=60'
    }
  ]);

  // signals derived from reactive form
  search = signal('');
  category = signal('');
  level = signal('');

  filteredCourses = computed(() => {
    const q = this.search().trim().toLowerCase();
    const cat = this.category();
    const lvl = this.level();

    return this.allCourses().filter((c) => {
      const matchesSearch = !q || c.title.toLowerCase().includes(q) || c.teacherName.toLowerCase().includes(q);
      const matchesCat = !cat || c.categoryName === cat;
      const matchesLvl = !lvl || c.levelName === lvl;
      return matchesSearch && matchesCat && matchesLvl;
    });
  });

  constructor() {
    this.filtersForm.valueChanges.subscribe((v) => {
      this.search.set(v.search ?? '');
      this.category.set(v.category ?? '');
      this.level.set(v.level ?? '');
    });

    // simulate loading
    setTimeout(() => this.isLoading.set(false), 650);
  }

  clearFilters() {
    this.filtersForm.reset({ search: '', category: '', level: '' });
  }
}
<div class="min-h-screen bg-[#F8F9FA] py-8">
  <div class="mx-auto w-full max-w-7xl px-4">
    <div class="mb-8">
      <h1 class="text-3xl font-bold text-gray-900 sm:text-4xl">Catalogue de cours</h1>
      <p class="mt-2 text-gray-600">Filtrez par catégories et niveaux, puis choisissez un cours.</p>
    </div>

    <div class="grid gap-6 lg:grid-cols-12">
      <!-- Sidebar filters -->
      <aside class="lg:col-span-4 xl:col-span-3">
        <form [formGroup]="filtersForm" class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <div class="flex items-center justify-between">
            <h2 class="text-base font-semibold text-gray-900">Filtres</h2>
            <button
              type="button"
              (click)="clearFilters()"
              class="text-sm font-medium text-[#1A73E8] hover:text-[#1A73E8]/80">
              Réinitialiser
            </button>
          </div>

          <div class="mt-5 space-y-4">
            <div>
              <label class="block text-sm font-medium text-gray-700">Recherche</label>
              <input
                type="text"
                formControlName="search"
                placeholder="Titre ou professeur..."
                class="mt-2 w-full rounded-xl border border-gray-300 px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-[#1A73E8]" />
            </div>

            <div>
              <label class="block text-sm font-medium text-gray-700">Catégorie</label>
              <select
                formControlName="category"
                class="mt-2 w-full rounded-xl border border-gray-300 bg-white px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-[#1A73E8]">
                <option value="">Toutes</option>
                <option *ngFor="let cat of categories()" [value]="cat">{{ cat }}</option>
              </select>
            </div>

            <div>
              <label class="block text-sm font-medium text-gray-700">Niveau</label>
              <select
                formControlName="level"
                class="mt-2 w-full rounded-xl border border-gray-300 bg-white px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-[#1A73E8]">
                <option value="">Tous</option>
                <option *ngFor="let lvl of levels()" [value]="lvl">{{ lvl }}</option>
              </select>
            </div>
          </div>
        </form>
      </aside>

      <!-- Content -->
      <section class="lg:col-span-8 xl:col-span-9">
        <div class="mb-4 flex items-center justify-between">
          <p class="text-sm text-gray-600">
            <span class="font-semibold text-gray-900">{{ filteredCourses().length }}</span>
            cours trouvés
          </p>
        </div>

        <!-- Skeletons -->
        <div *ngIf="isLoading()" class="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
          <div *ngFor="let x of [1,2,3,4,5,6]" class="overflow-hidden rounded-2xl border border-gray-200 bg-white shadow-sm">
            <div class="aspect-video w-full animate-pulse bg-gray-200"></div>
            <div class="p-5">
              <div class="h-5 w-3/4 animate-pulse rounded bg-gray-200"></div>
              <div class="mt-3 h-4 w-1/2 animate-pulse rounded bg-gray-200"></div>
              <div class="mt-6 h-10 w-full animate-pulse rounded-xl bg-gray-200"></div>
            </div>
          </div>
        </div>

        <!-- Grid -->
        <div *ngIf="!isLoading()" class="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
          <app-course-card *ngFor="let course of filteredCourses()" [course]="course" />
        </div>

        <!-- Empty -->
        <div *ngIf="!isLoading() && filteredCourses().length === 0" class="mt-10 rounded-2xl border border-dashed border-gray-300 bg-white p-10 text-center">
          <h3 class="text-lg font-semibold text-gray-900">Aucun cours trouvé</h3>
          <p class="mt-2 text-sm text-gray-600">Essayez de modifier vos filtres.</p>
          <button
            type="button"
            (click)="clearFilters()"
            class="mt-5 inline-flex items-center justify-center rounded-xl bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] px-5 py-2.5 text-sm font-semibold text-white shadow-sm focus:outline-none focus:ring-2 focus:ring-[#1A73E8] focus:ring-offset-2">
            Réinitialiser les filtres
          </button>
        </div>
      </section>
    </div>
  </div>
</div>
